t = int(input())
for _ in range(t):
    n = int(input())
    if n <= 26:
        print(''.join(chr(ord('a')+i) for i in range(n)))
    else:
        # n odd: "a"*n works? No.
        # Use: 26 distinct chars + padding
        # Actually for n > 26, if n is odd use "a"*n
        if n % 2 == 1:
            print('a' * n)
        else:
            print('a' * (n-1) + 'b')

